import React from 'react';
import { BrowserRouter as Router, Route, Routers } from 'react-router-dom';
import Header from './components/Header';
import Home from './components/Home';
import Upload from './components/Upload';
import Results from './components/Result';
import ImageProject from './components/ImageProject'; // Create this component
import AudioProject from './components/AudioProject'; // Create this component
import PoseProject from './components/PoseProject'; // Create this component

const App = () => {
    return (
        <Router>
            <Header />
            <Routers>
                <Route path="/" exact component={Home} />
                <Route path="/upload" component={Upload} />
                <Route path="/result" component={Result} />
                <Route path="/image-project" component={ImageProject} />
                <Route path="/audio-project" component={AudioProject} />
                <Route path="/pose-project" component={PoseProject} />
            </Routers>
        </Router>
    );
};

export default App;
